// Primary CTA: green bg, black text
// Shared button styles
const BTN_PRIMARY_STYLE = {
  fontFamily: "'Montserrat', sans-serif",
  background: C.green,
  color: "#000000",
  fontWeight: 700,
  fontSize: 12,
  letterSpacing: "0.14em",
  textTransform: "uppercase",
  border: "none",
  borderRadius: 999,
  padding: "14px 28px",
  cursor: "pointer",
  display: "inline-flex",
  alignItems: "center",
  gap: 8,
  transition: "filter 0.2s ease, transform 0.15s ease",
  textDecoration: "none",
};

const BTN_HOVER_IN  = e => { e.currentTarget.style.filter = "brightness(1.12)"; e.currentTarget.style.transform = "scale(1.01)"; };
const BTN_HOVER_OUT = e => { e.currentTarget.style.filter = "brightness(1)";    e.currentTarget.style.transform = "scale(1)"; };
const BTN_DOWN      = e => { e.currentTarget.style.transform = "scale(0.98)"; };
const BTN_UP        = e => { e.currentTarget.style.transform = "scale(1.01)"; };

// BtnPrimary — renders <a> for external URLs, <button> for onClick handlers
function BtnPrimary({ children, onClick, href, full = false }) {
  const style = { ...BTN_PRIMARY_STYLE, width: full ? "100%" : "auto", justifyContent: full ? "center" : "flex-start" };

  if (href) {
    return (
      <a href={href} target="_blank" rel="noopener noreferrer"
         style={style}
         onMouseEnter={BTN_HOVER_IN} onMouseLeave={BTN_HOVER_OUT}
         onMouseDown={BTN_DOWN} onMouseUp={BTN_UP}>
        {children}
        <ArrowRight size={13} color="#000000" />
      </a>
    );
  }

  return (
    <button onClick={onClick} style={{ ...style, appearance: "none" }}
            onMouseEnter={BTN_HOVER_IN} onMouseLeave={BTN_HOVER_OUT}
            onMouseDown={BTN_DOWN} onMouseUp={BTN_UP}>
      {children}
      <ArrowRight size={13} color="#000000" />
    </button>
  );
}

// Secondary CTA: outlined, white text
function BtnGhost({ children, onClick, href, full = false }) {
  const style = {
    fontFamily: "'Montserrat', sans-serif",
    background: "transparent",
    color: C.white,
    fontWeight: 600,
    fontSize: 12,
    letterSpacing: "0.14em",
    textTransform: "uppercase",
    border: "1px solid rgba(255,255,255,0.22)",
    borderRadius: 999,
    padding: "14px 28px",
    cursor: "pointer",
    display: "inline-flex",
    alignItems: "center",
    gap: 8,
    transition: "border-color 0.2s ease, color 0.2s ease",
    width: full ? "100%" : "auto",
    justifyContent: full ? "center" : "flex-start",
    textDecoration: "none",
  };
  const hIn  = e => { e.currentTarget.style.borderColor = C.green; e.currentTarget.style.color = C.green; };
  const hOut = e => { e.currentTarget.style.borderColor = "rgba(255,255,255,0.22)"; e.currentTarget.style.color = C.white; };

  if (href) {
    return <a href={href} target="_blank" rel="noopener noreferrer" style={style} onMouseEnter={hIn} onMouseLeave={hOut}>{children}</a>;
  }
  return (
    <button onClick={onClick} style={style} onMouseEnter={hIn} onMouseLeave={hOut}>
      {children}
    </button>
  );
}

