// Stateful social icon button that handles hover colour change
function SocialLink({ Icon, href, label }) {
  const [hovered, setHovered] = useState(false);
  return (
    <a href={href} target="_blank" rel="noopener noreferrer" aria-label={label}
       style={{ display: "flex", alignItems: "center", justifyContent: "center",
                width: 36, height: 36, borderRadius: "50%",
                background: hovered ? "rgba(126,213,151,0.12)" : "rgba(255,255,255,0.06)",
                border: `1px solid ${hovered ? "rgba(126,213,151,0.4)" : "rgba(255,255,255,0.1)"}`,
                transition: "all 0.2s ease", textDecoration: "none" }}
       onMouseEnter={() => setHovered(true)}
       onMouseLeave={() => setHovered(false)}>
      <Icon size={16} color={hovered ? C.green : "rgba(255,255,255,0.5)"} />
    </a>
  );
}

