// ─── Carousel ─────────────────────────────────────────────────────────────────
function ReviewCarousel({ reviews }) {
  const [idx, setIdx] = useState(0);
  const trackRef = useRef(null);
  const VISIBLE = 3; // cards shown at once on desktop (JS drives mobile via swipe)

  // Touch / drag swipe
  const dragStart = useRef(null);
  const onTouchStart = e => { dragStart.current = e.touches[0].clientX; };
  const onTouchEnd = e => {
    if (dragStart.current === null) return;
    const delta = dragStart.current - e.changedTouches[0].clientX;
    if (Math.abs(delta) > 40) delta > 0 ? next() : prev();
    dragStart.current = null;
  };

  const max = Math.max(0, reviews.length - VISIBLE);
  const prev = () => setIdx(i => Math.max(0, i - 1));
  const next = () => setIdx(i => Math.min(max, i + 1));

  return (
    <div>
      {/* Track */}
      <div style={{ overflow: "hidden" }}
           onTouchStart={onTouchStart} onTouchEnd={onTouchEnd}>
        <div
          ref={trackRef}
          style={{
            display: "flex",
            gap: 20,
            transition: "transform 0.5s cubic-bezier(.16,1,.3,1)",
            transform: `translateX(calc(-${idx} * (min(340px, 90vw) + 20px)))`,
          }}
        >
          {reviews.map((r, i) => (
            <div key={i} style={{
              flexShrink: 0,
              width: "clamp(280px, 32%, 340px)",
              background: C.card,
              border: `1px solid ${C.border}`,
              borderRadius: 20,
              padding: "28px 28px 24px",
              display: "flex", flexDirection: "column", justifyContent: "space-between",
            }}>
              <div>
                <Stars n={r.stars} />
                <p style={{ fontFamily: "'Poppins', sans-serif", color: C.white,
                            fontSize: 14, fontWeight: 300, lineHeight: 1.7,
                            fontStyle: "italic", marginBottom: 24 }}>
                  "{r.quote}"
                </p>
              </div>
              <div style={{ display: "flex", alignItems: "flex-end",
                            justifyContent: "space-between", flexWrap: "wrap", gap: 8 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                  <div style={{ width: 36, height: 36, borderRadius: "50%",
                                background: "rgba(126,213,151,0.1)",
                                border: "1px solid rgba(126,213,151,0.2)",
                                display: "flex", alignItems: "center", justifyContent: "center",
                                flexShrink: 0 }}>
                    <span style={{ fontFamily: "'Montserrat', sans-serif",
                                   color: C.green, fontSize: 14, fontWeight: 700 }}>
                      {r.name[0]}
                    </span>
                  </div>
                  <div>
                    <p style={{ fontFamily: "'Montserrat', sans-serif", color: C.white,
                                fontSize: 13, fontWeight: 600 }}>{r.name}</p>
                    {(r.goal || r.duration) && (
                      <p style={{ fontFamily: "'Poppins', sans-serif", color: C.green,
                                  fontSize: 11, marginTop: 2 }}>
                        {[r.goal, r.duration].filter(Boolean).join(" · ")}
                      </p>
                    )}
                  </div>
                </div>
                {r.goal && <Pill>{r.goal}</Pill>}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Navigation */}
      <div style={{ display: "flex", alignItems: "center",
                    justifyContent: "space-between", marginTop: 28 }}>
        {/* Dots */}
        <div style={{ display: "flex", gap: 8 }}>
          {Array.from({ length: max + 1 }).map((_, i) => (
            <button key={i} onClick={() => setIdx(i)} style={{
              width: i === idx ? 24 : 8, height: 8,
              borderRadius: 99,
              background: i === idx ? C.green : "rgba(255,255,255,0.18)",
              border: "none", cursor: "pointer", padding: 0,
              transition: "all 0.3s ease",
            }} />
          ))}
        </div>
        {/* Arrow buttons */}
        <div style={{ display: "flex", gap: 10 }}>
          {[
            { fn: prev, Icon: ArrowLeft, disabled: idx === 0 },
            { fn: next, Icon: ArrowRight, disabled: idx >= max },
          ].map(({ fn, Icon, disabled }, i) => (
            <button key={i} onClick={fn} disabled={disabled} style={{
              width: 42, height: 42, borderRadius: "50%",
              background: "transparent",
              border: `1px solid ${disabled ? "rgba(255,255,255,0.1)" : "rgba(255,255,255,0.25)"}`,
              cursor: disabled ? "not-allowed" : "pointer",
              display: "flex", alignItems: "center", justifyContent: "center",
              transition: "border-color 0.2s, background 0.2s",
              opacity: disabled ? 0.35 : 1,
            }}
              onMouseEnter={e => { if (!disabled) e.currentTarget.style.borderColor = C.green; }}
              onMouseLeave={e => { if (!disabled) e.currentTarget.style.borderColor = "rgba(255,255,255,0.25)"; }}
            >
              <Icon size={15} color={disabled ? "rgba(255,255,255,0.4)" : C.white} />
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

