// Generate a personalised recommendation text based on the specific answers given
function buildRecommendation(winner, answers) {
  const goal       = answers.goal       || "";
  const experience = answers.experience || "";
  const location   = answers.location   || "";
  const support    = answers.support    || "";
  const challenge  = answers.challenge  || "";

  if (winner === "o") {
    const goalLine = goal === "Lose body fat"
      ? "You want to lose body fat"
      : goal === "Build muscle and strength"
      ? "You want to build muscle and strength"
      : goal === "Improve my overall fitness"
      ? "You want to improve your overall fitness"
      : "You want to learn to train properly";

    const challengeLine = challenge === "Staying consistent"
      ? "Consistency is currently your biggest challenge, and that is exactly what Online Coaching is built around."
      : challenge === "Lack of structure"
      ? "You have said that structure is what you are missing, and Online Coaching gives you that on a weekly basis."
      : challenge === "I have hit a plateau"
      ? "You have hit a plateau, which usually means your plan needs adjusting. Regular check-ins mean that happens automatically."
      : "Weekly check-ins and ongoing support will help you stay on track and keep progressing.";

    const locationLine = location === "At home"
      ? "You train from home, so the programme will be built around your setup."
      : location === "At a gym"
      ? "You train at a gym, so your programme will be built to make the most of that."
      : "";

    return `Based on your answers, I would recommend Online Coaching.

${goalLine}, and ${challengeLine}${locationLine ? " " + locationLine : ""}

Rather than simply handing you a plan and leaving you to get on with it, Online Coaching means your programme evolves with you. Weekly check-ins, nutrition support and regular adjustments keep everything moving in the right direction.`;
  }

  if (winner === "p") {
    const goalLine = goal === "Lose body fat"
      ? "You want to lose body fat"
      : goal === "Build muscle and strength"
      ? "You want to build muscle and strength"
      : goal === "Improve my overall fitness"
      ? "You want to improve your overall fitness"
      : "You want a clear, structured approach to training";

    const supportLine = support === "Just a plan to follow on my own"
      ? "You have told me you are happy to train independently and just need a solid plan to follow."
      : "You want something structured that you can work through on your own terms.";

    const locationLine = location === "At home"
      ? " Your programme will be built around your home setup."
      : location === "At a gym"
      ? " Your programme will be built around your gym access."
      : "";

    return `Based on your answers, I would recommend a Personalised Programme.

${goalLine}, and ${supportLine}${locationLine}

A Personalised Programme gives you a complete, structured training plan built specifically around your goals, your schedule and your equipment. It is delivered through Everfit with video guidance, so you always know exactly what you are doing and why.`;
  }

  // pt
  const expLine = experience === "I am a complete beginner"
    ? "You are new to training, which means getting your technique right from the start will make a huge difference long term."
    : experience === "I have trained on and off"
    ? "You have some training experience but have not always been consistent."
    : "You have training experience but want proper coaching to take things further.";

  const supportLine = support === "Hands-on coaching every session"
    ? "You have said you want hands-on coaching in every session, which is exactly what Personal Training provides."
    : "In-person coaching gives you direct feedback and accountability that is difficult to replicate remotely.";

  return `Based on your answers, I would recommend Personal Training.

${expLine} ${supportLine}

Sessions take place in Northampton and start with a free consultation so we can talk through your goals before committing to anything. Every session is planned around your progress rather than a fixed routine.`;
}

function QuizModal({ onClose, go }) {
  const [step, setStep] = useState(0);
  const [scores, setScores] = useState({ o: 0, p: 0, pt: 0 });
  const [answers, setAnswers] = useState({});
  const [result, setResult] = useState(null);
  const [recommendation, setRecommendation] = useState("");

  const pick = opt => {
    const q = QUIZ[step];
    const newAnswers = { ...answers, [q.key]: opt.l };
    setAnswers(newAnswers);
    const next = { o: scores.o + opt.v.o, p: scores.p + opt.v.p, pt: scores.pt + opt.v.pt };
    setScores(next);
    if (step + 1 < QUIZ.length) {
      setStep(step + 1);
    } else {
      const winner = Object.entries(next).sort((a, b) => b[1] - a[1])[0][0];
      setResult(winner);
      setRecommendation(buildRecommendation(winner, newAnswers));
    }
  };

  const reset = () => {
    setStep(0);
    setScores({ o: 0, p: 0, pt: 0 });
    setAnswers({});
    setResult(null);
    setRecommendation("");
  };

  const RESULT_TITLES = { o: "Online Coaching", p: "Personalised Programme", pt: "Personal Training" };
  const RESULT_PAGES  = { o: "online", p: "programmes", pt: "pt" };
  const RESULT_CTA    = { o: "View Online Coaching", p: "View Personalised Programmes", pt: "View Personal Training" };

  const pct = result ? 100 : Math.round((step / QUIZ.length) * 100);

  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 200,
                  display: "flex", alignItems: "flex-end", justifyContent: "center" }}
         className="sm-center-modal">
      {/* Backdrop */}
      <div onClick={onClose}
           style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,0.8)",
                    backdropFilter: "blur(8px)" }} />
      {/* Sheet */}
      <div style={{ position: "relative", width: "100%", maxWidth: 520,
                    background: "#111111", border: `1px solid ${C.border}`,
                    borderRadius: "24px 24px 0 0", padding: "32px 28px",
                    maxHeight: "92vh", overflowY: "auto" }}>
        {/* Progress */}
        <div style={{ display: "flex", alignItems: "center", gap: 16, marginBottom: 32 }}>
          <div style={{ flex: 1, height: 3, background: "rgba(255,255,255,0.1)",
                        borderRadius: 99, overflow: "hidden" }}>
            <div style={{ height: "100%", width: `${pct}%`, background: C.green,
                          transition: "width 0.5s ease", borderRadius: 99 }} />
          </div>
          <button onClick={onClose}
                  style={{ background: "none", border: "none", cursor: "pointer",
                           color: "rgba(255,255,255,0.4)", transition: "color 0.2s" }}>
            <X size={18} color="rgba(255,255,255,0.5)" />
          </button>
        </div>

        {!result ? (
          <>
            <p style={{ fontFamily: "'Montserrat', sans-serif", color: C.green,
                        fontSize: 10, fontWeight: 600, letterSpacing: "0.2em",
                        textTransform: "uppercase", marginBottom: 10 }}>
              Question {step + 1} of {QUIZ.length}
            </p>
            <H3 style={{ fontSize: 20, marginBottom: 24 }}>{QUIZ[step].q}</H3>
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              {QUIZ[step].opts.map(opt => (
                <button key={opt.l} onClick={() => pick(opt)}
                        style={{ background: "none",
                                 border: `1px solid rgba(255,255,255,0.12)`,
                                 borderRadius: 14, padding: "14px 18px", cursor: "pointer",
                                 textAlign: "left", fontFamily: "'Poppins', sans-serif",
                                 color: C.white, fontSize: 14, fontWeight: 300,
                                 transition: "border-color 0.2s, background 0.2s" }}
                        onMouseEnter={e => { e.currentTarget.style.borderColor = "rgba(126,213,151,0.5)"; e.currentTarget.style.background = "rgba(126,213,151,0.05)"; }}
                        onMouseLeave={e => { e.currentTarget.style.borderColor = "rgba(255,255,255,0.12)"; e.currentTarget.style.background = "none"; }}>
                  {opt.l}
                </button>
              ))}
            </div>
            {step > 0 && (
              <button onClick={() => setStep(step - 1)}
                      style={{ marginTop: 24, display: "flex", alignItems: "center", gap: 8,
                               background: "none", border: "none", cursor: "pointer",
                               fontFamily: "'Montserrat', sans-serif", color: "rgba(255,255,255,0.3)",
                               fontSize: 11, fontWeight: 600, letterSpacing: "0.12em",
                               textTransform: "uppercase", transition: "color 0.2s" }}
                      onMouseEnter={e => { e.currentTarget.style.color = C.white; }}
                      onMouseLeave={e => { e.currentTarget.style.color = "rgba(255,255,255,0.3)"; }}>
                <ArrowLeft size={12} color="currentColor" /> Back
              </button>
            )}
          </>
        ) : (
          <>
            <p style={{ fontFamily: "'Montserrat', sans-serif", color: C.green,
                        fontSize: 10, fontWeight: 600, letterSpacing: "0.2em",
                        textTransform: "uppercase", marginBottom: 10 }}>
              My recommendation
            </p>
            <H3 style={{ fontSize: 26, marginBottom: 14 }}>{RESULT_TITLES[result]}</H3>
            <div style={{ marginBottom: 28 }}>
              {recommendation.split("\n\n").map((para, i) => (
                <Body key={i} style={{ fontSize: 14, marginBottom: i < recommendation.split("\n\n").length - 1 ? 12 : 0 }}>
                  {para}
                </Body>
              ))}
            </div>
            <BtnPrimary full onClick={() => { go(RESULT_PAGES[result]); onClose(); }}>
              {RESULT_CTA[result]}
            </BtnPrimary>
            <button onClick={reset}
                    style={{ marginTop: 16, width: "100%", textAlign: "center",
                             background: "none", border: "none", cursor: "pointer",
                             fontFamily: "'Montserrat', sans-serif",
                             color: "rgba(255,255,255,0.3)", fontSize: 11,
                             fontWeight: 600, letterSpacing: "0.12em", textTransform: "uppercase",
                             transition: "color 0.2s" }}
                    onMouseEnter={e => { e.currentTarget.style.color = C.white; }}
                    onMouseLeave={e => { e.currentTarget.style.color = "rgba(255,255,255,0.3)"; }}>
              Start again
            </button>
          </>
        )}
      </div>
      <style>{`
        @media (min-width: 640px) {
          .sm-center-modal { align-items: center !important; }
          .sm-center-modal > div:last-child { border-radius: 24px !important; }
        }
      `}</style>
    </div>
  );
}


