// ROOT APP
// ═══════════════════════════════════════════════════════════════════════════════
export default function App() {
  useGlobalStyles();
  const [page, setPage] = useState("home");
  const [quiz, setQuiz] = useState(false);
  const topRef = useRef(null);

  const go = p => {
    setPage(p);
    // Belt-and-braces scroll reset — covers window, document and the container ref
    try { window.scrollTo(0, 0); } catch(e) {}
    try { document.documentElement.scrollTop = 0; } catch(e) {}
    try { document.body.scrollTop = 0; } catch(e) {}
    // Also scroll the wrapper element itself (handles iframe/sandboxed envs)
    setTimeout(() => {
      try { topRef.current?.scrollIntoView({ block: "start", behavior: "instant" }); } catch(e) {}
      try { window.scrollTo(0, 0); } catch(e) {}
      try { document.documentElement.scrollTop = 0; } catch(e) {}
    }, 0);
  };

  const isLegal = ["terms","privacy","cookies"].includes(page);

  return (
    <div ref={topRef} style={{ background: C.bg, minHeight: "100vh", color: C.white }}>
      <Nav go={go} page={page} hideServices={isLegal} />
      {/* key={page} forces React to fully unmount/remount the page — kills any scroll state */}
      <div key={page}>
        {page === "home"       && <Home go={go} openQuiz={() => setQuiz(true)} />}
        {page === "online"     && <OnlinePage openQuiz={() => setQuiz(true)} go={go} />}
        {page === "programmes" && <ProgrammesPage openQuiz={() => setQuiz(true)} go={go} />}
        {page === "pt"         && <PTPage openQuiz={() => setQuiz(true)} go={go} />}
        {page === "terms"      && <TermsPage go={go} />}
        {page === "privacy"    && <PrivacyPage go={go} />}
        {page === "cookies"    && <CookiesPage go={go} />}
      </div>
      <Footer go={go} />
      {quiz && <QuizModal onClose={() => setQuiz(false)} go={go} />}
    </div>
  );
}
